import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

const API_BASE_URL = 'http://localhost:8000/api/v1/emissions';

function AIModelEmissions() {
  const [emissions, setEmissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedModel, setSelectedModel] = useState(null);

  // Simulation State
  const [simulating, setSimulating] = useState(null); // model name
  const [simProgress, setSimProgress] = useState(0);
  const [simValues, setSimValues] = useState({ co2: 0, energy: 0, runtime: 0 });

  const simIntervalRef = useRef(null);

  useEffect(() => {
    fetchEmissions();
    return () => clearInterval(simIntervalRef.current);
  }, []);

  const fetchEmissions = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/ai-models/all`);
      setEmissions(res.data.data || []);
      setLoading(false);
    } catch (err) {
      console.error('Error fetching AI emissions:', err);
      setError(err.message);
      setLoading(false);
    }
  };

  const startSimulation = (model) => {
    if (simulating) return;

    setSimulating(model.model_name);
    setSimProgress(0);
    setSimValues({ co2: 0, energy: 0, runtime: 0 });

    const duration = 5000; // 5 seconds simulation
    const steps = 50;
    const interval = duration / steps;

    let currentStep = 0;

    simIntervalRef.current = setInterval(() => {
      currentStep++;
      const progress = (currentStep / steps) * 100;
      setSimProgress(progress);

      setSimValues({
        co2: (model.co2_kg * (currentStep / steps)).toFixed(4),
        energy: (model.energy_kwh * (currentStep / steps)).toFixed(4),
        runtime: (model.runtime_minutes * (currentStep / steps)).toFixed(2)
      });

      if (currentStep >= steps) {
        clearInterval(simIntervalRef.current);
        setTimeout(() => {
          setSimulating(null);
          setSelectedModel(model.model_name);
        }, 1000);
      }
    }, interval);
  };

  const formatNumber = (value, decimals = 2) => {
    if (value === null || value === undefined || isNaN(value)) return '0.00';
    return parseFloat(value).toFixed(decimals);
  };

  if (loading) {
    return (
      <div className="container">
        <div className="shimmer glass-card" style={{ height: '300px', marginBottom: '24px' }}></div>
      </div>
    );
  }

  return (
    <div className="fade-in" style={{ padding: '20px' }}>
      {/* Header Section */}
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: '40px' }}>
        <div style={{
          width: '6px',
          height: '40px',
          background: 'var(--success-gradient)',
          borderRadius: '3px',
          marginRight: '20px',
          boxShadow: '0 0 15px var(--accent-green)'
        }}></div>
        <div>
          <h2 style={{ fontSize: '2.5rem', fontWeight: 800, margin: 0, letterSpacing: '-1px' }}>
            AI Model <span className="gradient-text">CO₂ Intelligence</span>
          </h2>
          <p style={{ color: 'var(--text-secondary)', margin: '5px 0 0 0' }}>
            Real-time emission monitoring and impact analysis for deep learning workloads.
          </p>
        </div>
      </div>

      {/* Overview Stats */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
        gap: '20px',
        marginBottom: '40px'
      }}>
        <div className="glass-card" style={{ padding: '24px', borderLeft: '4px solid var(--accent-blue)' }}>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', marginBottom: '8px' }}>Active Models</p>
          <h3 style={{ fontSize: '2rem', margin: 0 }}>{emissions.length} <span style={{ fontSize: '1rem', opacity: 0.6 }}>Systems</span></h3>
        </div>
        <div className="glass-card" style={{ padding: '24px', borderLeft: '4px solid var(--accent-green)' }}>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', marginBottom: '8px' }}>Avg Efficiency</p>
          <h3 style={{ fontSize: '2rem', margin: 0 }}>94.2 <span style={{ fontSize: '1rem', opacity: 0.6 }}>%</span></h3>
        </div>
        <div className="glass-card" style={{ padding: '24px', borderLeft: '4px solid var(--accent-orange)' }}>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', marginBottom: '8px' }}>Global Impact</p>
          <h3 style={{ fontSize: '2rem', margin: 0 }}>Low <span style={{ fontSize: '1rem', opacity: 0.6 }}>Grade</span></h3>
        </div>
      </div>

      {/* Interactive Control Center */}
      <div style={{ marginBottom: '40px' }}>
        <h3 style={{ fontSize: '1.5rem', marginBottom: '20px', display: 'flex', alignItems: 'center' }}>
          <span style={{ marginRight: '10px' }}>🚀</span> Model Control Center
        </h3>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
          gap: '24px'
        }}>
          {emissions.map((model, idx) => (
            <div
              key={idx}
              className={`glass-card ${simulating === model.model_name ? 'pulse' : ''}`}
              style={{
                padding: '24px',
                position: 'relative',
                overflow: 'hidden',
                border: simulating === model.model_name ? '2px solid var(--accent-blue)' : '1px solid rgba(255,255,255,0.1)',
                transform: selectedModel === model.model_name ? 'scale(1.02)' : 'scale(1)',
                boxShadow: selectedModel === model.model_name ? 'var(--shadow-glow)' : 'var(--shadow-md)'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
                <div>
                  <h4 style={{ fontSize: '1.3rem', margin: 0 }}>{model.model_name}</h4>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.8rem' }}>{model.model_type}</p>
                </div>
                <div style={{
                  padding: '4px 12px',
                  borderRadius: '20px',
                  background: 'rgba(255,255,255,0.1)',
                  fontSize: '0.75rem',
                  fontWeight: 600
                }}>
                  {model.hardware}
                </div>
              </div>

              <div style={{ display: 'flex', gap: '20px', marginBottom: '24px' }}>
                <div style={{ flex: 1 }}>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.75rem' }}>CO₂ Baseline</p>
                  <p style={{ fontSize: '1.2rem', fontWeight: 700, color: 'var(--accent-blue)' }}>{formatNumber(model.co2_kg, 3)} kg</p>
                </div>
                <div style={{ flex: 1 }}>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.75rem' }}>Energy Est.</p>
                  <p style={{ fontSize: '1.2rem', fontWeight: 700, color: 'var(--accent-orange)' }}>{formatNumber(model.energy_kwh, 3)} kWh</p>
                </div>
              </div>

              {/* Special Animation Button */}
              <button
                onClick={() => startSimulation(model)}
                disabled={simulating !== null}
                style={{
                  width: '100%',
                  padding: '12px',
                  borderRadius: '12px',
                  border: 'none',
                  background: simulating === model.model_name ? 'var(--bg-secondary)' : 'var(--success-gradient)',
                  color: '#fff',
                  fontWeight: 700,
                  cursor: simulating !== null ? 'not-allowed' : 'pointer',
                  transition: 'all 0.3s ease',
                  boxShadow: simulating === model.model_name ? 'none' : '0 4px 15px rgba(79, 172, 254, 0.4)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '10px'
                }}
                className="btn-hover-effect"
              >
                {simulating === model.model_name ? (
                  <>
                    <div className="spinner" style={{ width: '16px', height: '16px', border: '2px solid #fff', borderTop: '2px solid transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
                    Calculating...
                  </>
                ) : (
                  <>
                    <span>⚡ Run Real-Time Check</span>
                  </>
                )}
              </button>

              {/* Progress Bar (Visible only during simulation) */}
              {simulating === model.model_name && (
                <div style={{
                  marginTop: '16px',
                  height: '4px',
                  background: 'rgba(255,255,255,0.1)',
                  borderRadius: '2px',
                  overflow: 'hidden'
                }}>
                  <div style={{
                    width: `${simProgress}%`,
                    height: '100%',
                    background: 'var(--accent-green)',
                    boxShadow: '0 0 10px var(--accent-green)',
                    transition: 'width 0.1s linear'
                  }}></div>
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Analysis Result (Real-time Area) */}
      {(selectedModel || simulating) && (
        <div className="glass-card fade-in" style={{
          padding: '40px',
          border: '1px solid var(--accent-blue)',
          background: 'rgba(79, 172, 254, 0.05)',
          position: 'relative'
        }}>
          <div style={{ display: 'flex', gap: '40px', flexWrap: 'wrap' }}>
            <div style={{ flex: '1 1 300px' }}>
              <h3 style={{ fontSize: '1.8rem', marginBottom: '10px' }}>
                {simulating ? `Analyzing ${simulating}...` : `Result for ${selectedModel}`}
              </h3>
              <p style={{ color: 'var(--text-secondary)', marginBottom: '30px' }}>
                {simulating ? 'Processing workload telemetry and calculating carbon footprint...' : 'Simulation complete. Technical report generated based on system metrics.'}
              </p>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                <div style={{ padding: '20px', borderRadius: '16px', background: 'rgba(255,255,255,0.05)' }}>
                  <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Live CO₂ Output</p>
                  <p style={{ fontSize: '2.5rem', fontWeight: 800, color: 'var(--accent-blue)', margin: 0 }}>
                    {simulating ? simValues.co2 : formatNumber(emissions.find(m => m.model_name === selectedModel)?.co2_kg, 4)}
                    <span style={{ fontSize: '1rem', marginLeft: '8px' }}>kg</span>
                  </p>
                </div>
                <div style={{ padding: '20px', borderRadius: '16px', background: 'rgba(255,255,255,0.05)' }}>
                  <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Energy Consumption</p>
                  <p style={{ fontSize: '2.5rem', fontWeight: 800, color: 'var(--accent-orange)', margin: 0 }}>
                    {simulating ? simValues.energy : formatNumber(emissions.find(m => m.model_name === selectedModel)?.energy_kwh, 4)}
                    <span style={{ fontSize: '1rem', marginLeft: '8px' }}>kWh</span>
                  </p>
                </div>
              </div>
            </div>

            <div style={{ flex: '1 1 400px', padding: '30px', borderRadius: '20px', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.05)' }}>
              <h4 style={{ marginBottom: '20px', color: 'var(--accent-green)' }}>Optimization Suggestions</h4>
              <ul style={{ listStyle: 'none', padding: 0, fontSize: '0.9rem' }}>
                <li style={{ marginBottom: '12px', display: 'flex', gap: '10px' }}>
                  <span>✅</span> Use specific quantization (INT8) to reduce energy by 40%
                </li>
                <li style={{ marginBottom: '12px', display: 'flex', gap: '10px' }}>
                  <span>✅</span> Schedule heavy training during grid low-carbon hours
                </li>
                <li style={{ marginBottom: '12px', display: 'flex', gap: '10px' }}>
                  <span>✅</span> Optimize data loader pipeline to minimize CPU idle time
                </li>
              </ul>
            </div>
          </div>

          {/* Decorative Corner Icon */}
          <div style={{ position: 'absolute', top: '20px', right: '20px', fontSize: '3rem', opacity: 0.1 }}>
            🌍
          </div>
        </div>
      )}

      {/* Styled Animations */}
      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        .btn-hover-effect:hover {
          transform: translateY(-2px);
          filter: brightness(1.1);
        }
        .btn-hover-effect:active {
          transform: translateY(0);
        }
        .pulse {
          animation: pulseShadow 2s infinite;
        }
        @keyframes pulseShadow {
          0% { box-shadow: 0 0 0 0 rgba(79, 172, 254, 0.4); }
          70% { box-shadow: 0 0 0 15px rgba(79, 172, 254, 0); }
          100% { box-shadow: 0 0 0 0 rgba(79, 172, 254, 0); }
        }
      `}</style>
    </div>
  );
}

export default AIModelEmissions;
